/* Hide the default Quarto title/author header */ #title-block-header { display: none; }
/* Custom three-column grid layout */ .pub-grid { display: grid; grid-template-columns: 100px 1fr 280px; gap: 30px; align-items: start; padding: 40px 0; border-bottom: 1px solid #ddd; }
/* Column 1: Index and Journal Link */ .pub-index-col { text-align: left; }
.pub-number { font-size: 1.6em; font-weight: bold; color: #222; margin-bottom: 8px; }
.pub-url-link { font-size: 0.85em; color: #0366d6; text-decoration: none; display: block; }
.pub-url-link:hover { text-decoration: underline; }
/* Column 2: Full Citation */ .pub-cite-col { font-size: 1.05em; line-height: 1.5; color: #333; }
.pub-title-text { font-weight: bold; font-size: 1.15em; display: block; margin-bottom: 8px; color: #000; }
.me-underline { text-decoration: underline; }
/* Column 3: TOC Figure */ .pub-image-col img { width: 100%; height: auto; border: 1px solid #eee; box-shadow: 2px 2px 5px rgba(0,0,0,0.05); border-radius: 4px; }
/* Mobile Responsiveness */ @media (max-width: 800px) { .pub-grid { grid-template-columns: 1fr; gap: 20px; } }



